def insert_sample_data():
    """插入已识别的样本数据"""
    print(f"\n正在插入已识别的{len(SAMPLE_DATA)}张样本数据...")
    success_count = 0
    for data in SAMPLE_DATA:
        if insert_result(
            filename=data["filename"],
            raw_text=data["raw_text"],
            date=data["date"],
            pe_ttm=data["pe_ttm"],
            std_plus=data["std_plus"],
            avg=data["avg"],
            std_minus=data["std_minus"],
            close_price=data["close_price"]
        ):
            success_count += 1
            print(f"  [OK] {data['filename']}: {data['date'] or '无数据'}")
    print(f"\n[OK] 成功插入 {success_count} 条样本数据")

def main():
    """主函数"""
    print("=" * 50)
    print("AI OCR 文字识别程序")
    print("=" * 50)

    # 创建表
    create_table()

    # 插入已识别的样本数据
    insert_sample_data()

    # 获取所有图片
    image_files = get_image_files()
    print(f"\n共找到 {len(image_files)} 张图片")

    # 显示数据摘要
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute("SELECT COUNT(*) FROM ocr_results")
    count = cursor.fetchone()[0]
    conn.close()
    print(f"数据库中已有 {count} 条记录")
    print(f"还需识别 {len(image_files) - count} 张图片")

    print("\n" + "=" * 50)
    print("注意：剩余图片需要配置AI API密钥才能自动识别")
    print("请根据您的API提供商修改 extract_text_with_ai() 函数")
    print("=" * 50)

if __name__ == "__main__":
    main()
